const zlib = require("node:zlib");
const { Buffer } = require("node:buffer");

function callbackPromise(invoke) {
    return new Promise((resolve, reject) => {
        invoke((err, value) => {
            if (err) {
                reject(err);
            } else {
                resolve(value);
            }
        });
    });
}

module.exports = async function probe() {
    const input = Buffer.from("hello-zlib", "utf8");
    const gzipped = await callbackPromise((cb) => zlib.gzip(input, cb));
    const gunzipped = await callbackPromise((cb) => zlib.gunzip(gzipped, cb));
    const text = Buffer.from(gunzipped).toString("utf8");
    return {
        roundTripText: text,
        gzipLengthOk: gzipped.length > 0 && gzipped.length < input.length + 64,
    };
};
